INSERT INTO `products` (`id`, `article_number`, `name`, `description`, `price`, `image`, `heat_level`, `rating`, `badge`, `image_url`, `origin`, `created_at`, `updated_at`, `category`, `stock`, `image2`, `image3`, `image4`, `supplier`, `weight_kg`) VALUES
(13, '13', '5 Stk. Räucherhaken Standard - Doppelfixierung', 'Mit zwei Haken für eine optimale Fixierung um das Rückgrat.\r\n\r\nDrahtdurchmesser: 3 mm\r\nLänge: 210 mm\r\nEdelstahl', 10.00, NULL, 1, 0.00, '', 'https://web.lweb.ch/usa/img/rauch_grill/13', 'Smoki', '2026-04-30 15:19:15', '2026-05-04 09:03:15', 'rauch-grill', 0, NULL, NULL, NULL, 'Smoki', 0.100),
(103, '103', 'Elektroheizung für Räucherofen, 2300Watt', 'Mit dieser Elektroheizung ist ein komfortables und sauberes Räuchern möglich.\r\n\r\nÜber einen Regler können Sie die gewünschte Temperatur anfahren, die Heizung schaltet sich dann automatisch zu und ab.\r\n\r\nDie Leistung: liegt mit 2300 Watt im oberen Bereich der verfügbaren Heizungen und ist damit auch für unsere Modelle bis 150cm geeignet. Da die Heizung in der Räucherkammer platziert wird, wird auch die Strahlungswärme der Heizwendeln genutzt.\r\n\r\nInkl. Kontrollleuchte\r\n\r\nKabellänge: 1,3 m\r\n\r\nVDE-Kennzeichnung\r\n\r\nPrüfungen nach DIN EN 60335-1 ICE 335-1\r\n\r\nMADE IN GERMANY\r\n\r\n \r\n\r\nFür die Modelle 80x40x27cm und 120x40x27cm brauchen Sie ein Aufnahmeblech. siehe Artikel Nr. 62', 129.00, NULL, 1, 0.00, '', 'https://web.lweb.ch/usa/img/rauch_grill/103', 'Smoki', '2026-04-30 15:19:15', '2026-04-30 15:19:15', 'rauch-grill', 1, NULL, NULL, NULL, 'Smoki', 2.000),
(104, '104', 'Gasbrenner 4,2kW mit Schlauch + Minderer f. Räucherofen', 'Gasheizung\r\n\r\npassend für Räucherofen Smoki\r\n\r\nFüße demontierbar, zum Einsatz in kleinere Schächte\r\n\r\nLeistung: 4200Watt, empfohlen ab 100cm Räucherofenhöhe.\r\n\r\nregelbar mit Schlauch und Druckminderer.', 129.00, NULL, 1, 0.00, '', 'https://web.lweb.ch/usa/img/rauch_grill/104', 'Smoki', '2026-04-30 15:19:15', '2026-04-30 15:19:15', 'rauch-grill', 1, NULL, NULL, NULL, 'Smoki', 2.000),
(149, '0000149', 'AR-6 Stinger taktischer vertikaler Vordergriff', 'Taktischer vertikaler Vordergriff für die Steambow AR-6 Stinger.\r\n\r\nFarbe: Schwarz', 19.00, NULL, 1, 0.00, '', 'https://web.lweb.ch/usa/img/armbrust_zubehor/0000149', 'Steambow', '2026-04-30 15:17:56', '2026-05-04 15:01:46', 'armbrust-zubehoer', 0, NULL, NULL, NULL, 'Steambow', 0.200),
(150, '0000150', 'Stinger Rotpunktvisier', 'Hochwertiges Rotpunktvisier für die AR-6 Stinger.\r\n\r\nKomplett aus Aluminium gefertigt. Wechselbares Absehen (Wahlweise: „Fadenkreuz“ für präzise Schüsse, „Kreis“ für schnelle Zielerfassung oder ein „Punkt“ um wenig vom Ziel zu verdecken) sowie wechselbare Farbe und Helligkeit des Absehens. Durch wahlweise Rot oder Grün hat man je nach Umgebung den bestmöglichen Kontrast. Die Helligkeitseinstellung ist vor allem bei schlechtem Licht notwendig um das Ziel nicht zu überstrahlen bzw. um die Nachtsicht nicht zu beeinträchtigen. Das Visier ist wiederholgenau einstellbar und bieten einen weiten Verstellbereich. Mit dem mitgelieferten Inbusschlüssel ist die Justage (und auch die Montage) blitzschnell erledigt.\r\n\r\nBatterien sind im Lieferumfang enthalten und haben eine lange Lebensdauer. Farbe: schwarz.', 78.00, NULL, 1, 0.00, '', 'https://web.lweb.ch/usa/img/armbrustzubehor/0000150', 'Steambow', '2026-04-30 15:17:56', '2026-05-05 09:56:11', 'zielvorrichtungen', 3, NULL, NULL, NULL, 'Steambow', 0.300),
(192, '0000192', 'Stinger taktische Waffenlampe', 'Taktische Waffenlampe für die seitliche Montage am AR-6 Stinger.\r\nIm Lieferumfang befindet sich zusätzlich eine passende Zubehörschiene und das notwen', 79.00, NULL, 1, 0.00, '', 'https://web.lweb.ch/usa/img/armbrustzubehor/0000192', 'Steambow', '2026-04-30 15:17:56', '2026-05-05 15:01:17', 'waffenlampen', 0, NULL, NULL, NULL, 'Steambow', 0.300),
(215, '0000215', 'Stinger Übungspfeile – Set aus 10 Stk.', 'Hochwertige Übungspfeile für die AR-6 Stinger. Blau eloxiert für gute Unterscheidbarkeit im Magazin.\r\n\r\nDie Pfeile sind komplett aus Aluminium geferti', 21.00, NULL, 1, 0.00, '', 'https://web.lweb.ch/usa/img/armbrustzubehor/0000215', 'Steambow', '2026-04-30 15:17:56', '2026-05-05 14:53:25', 'armbrustpfeile-und-bolzen', 0, NULL, NULL, NULL, 'Steambow', 0.300),
(250, '0000250', 'Stinger Jagdpfeile – Set aus 3 Stk.', 'Jagdpfeile mit scharfer Klinge – Set aus 3 Stk., passend für AR-6 Stinger – Schaft rot eloxiert.\r\n\r\nDurch den rot eloxierten Aluminium-Schaft ist eine', 39.00, NULL, 1, 0.00, '', 'https://web.lweb.ch/usa/img/armbrustzubehor/0000250', 'Steambow', '2026-04-30 15:17:56', '2026-05-05 10:02:02', 'armbrustpfeile-und-bolzen', 32, NULL, NULL, NULL, 'Steambow', 0.300),
(311, '0000311', 'Jagdpfeile für EK-Archery 5stk.', 'Jagdpfeile mit scharfer Klinge  – Set aus 5 Stk., passend für Ek-Archery Research™ Cobra System RX ADDER und Cobra System R9.\r\n\r\nDiese Jagdpfeile sind speziell für die Verwendung in Magazinen entwickelt: Absolute Zuverlässigkeit beim Repetiervorgang, hervorragende Flugeigenschaften und Präzision, sowie eine starke Wirkung im Ziel. Dank unserer langjährigen Erfahrung mit Armbrustjagd und speziell auch mit Repetierarmbrüsten wissen wir worauf es bei solchen Pfeilen ankommt.\r\n\r\nBalance und Schwerpunkt des Pfeils sind sorgsam entwickelt und für eine hervorragende und präzise Flugbahn optimiert. Die Pfeilspitze, also das Insert mit der Klinge, ist fest im Carbonschaft verklebt. Die Klinge befindet sich damit stets in Flucht mit Befiederung und Nocke und die Repetierarmbrust arbeitet absolut zuverlässig. Dennoch ist die Klinge verschraubt und kann ausgetauscht werden. Unsere Nocken fertigen wir aus hochwertigem Polymer, um jegliche Probleme bei Zuführung und Abschuss zu vermeiden. Pfeillänge, Befiederung sowie Geometrie und Größe der Klinge sind auf das Magazin der ADDER Repetierarmbrust abgestimmt. Diese Pfeile lassen sich jedoch auch mit den meisten einschüssigen Armbrüsten gut verwenden.\r\n\r\nHinweis: Diese Pfeile funktionieren sowohl im originalen 5-Schuss Magazin der ADDER also auch im Tuning-Magazin mit 7-Schuss und Schnelllader der Firma GoGun GmbH aus Deutschland.\r\n\r\nSchnittbreite: 22,5 mm\r\nGewicht des Pfeils: 13,3 Gramm (205 grains)\r\n\r\nDie Klinge ist aus rostfreiem Stahl gefertigt, ab Werk scharf angeschliffen und mit einer Dicke von 1 mm sehr robust ausgeführt.\r\n\r\nAchtung: Erkundigen Sie sich vor dem Kauf bzgl. der Jagd- und Waffengesetze in Ihrem Land. Die Jagd mit der Armbrust ist in vielen europäischen Ländern verboten! Unter Umständen gibt es auch Einschränkungen bzgl. Besitz und Führens solcher Pfeile.', 69.00, NULL, 1, 0.00, '', 'https://web.lweb.ch/usa/img/armbrustzubehor/0000311', 'Steambow', '2026-04-30 15:17:56', '2026-05-05 14:48:17', 'armbrustpfeile-und-bolzen', 1, NULL, NULL, NULL, 'Steambow', 0.200),
(362, '0000362', 'Stinger – taktische Lampe inkl. Universalhalterung', 'Taktische Lampe mit Universalhalterung für die AR-6 Serie.\r\n\r\nLieferumfang:\r\n\r\nTaktische Lampe\r\nBatterie\r\nUniversalhalterung\r\nSchrauben, Muttern und W', 91.00, NULL, 1, 0.00, '', 'https://web.lweb.ch/usa/img/armbrustzubehor/0000362', 'Steambow', '2026-04-30 15:17:56', '2026-05-13 14:28:57', 'waffenlampen', 11, NULL, NULL, NULL, 'Steambow', 0.300),
(376, '0000376', 'Steambow AR-6 Stinger II Tactical', 'Die neue AR-6 Stinger II ist da! – Vorbestellungen werden ab Mitte Oktober ausgeliefert!\r\nDamit dieses Produkt nach Deutschland verkauft werden kann,', 389.00, NULL, 1, 0.00, '', 'https://web.lweb.ch/usa/img/armbrust/0000376', 'Steambow', '2026-04-30 15:16:39', '2026-05-05 09:19:44', 'magazin-armbrust', 1, NULL, NULL, NULL, 'Steambow', 10.000),
(401, '0000401', 'Stinger Bodkinpfeile – Set aus 6 Stk.', 'Unsere Bodkinpfeile für die AR-6 Stinger wurden für maximale Durchdringungskraft konzipiert.\r\n\r\nMit einem Gewicht von 10,5 g / 162 grains pro Pfeil un', 39.00, NULL, 1, 0.00, '', 'https://web.lweb.ch/usa/img/armbrustzubehor/0000401', 'Steambow', '2026-04-30 15:17:56', '2026-05-05 14:53:13', 'armbrustpfeile-und-bolzen', 13, NULL, NULL, NULL, 'Steambow', 0.300),
(419, '0000419', 'AR-6 Stinger II – Wurfarme 55lbs', 'AR-6 Stinger II – Wurfarm TACTICAL – 55 lbs\r\n\r\nFür alle unsere Pfeiltypen geeignet – die schweren Ausführungen der Carbonpfeilen haben eine geringere Geschwindigkeit und eine kürzere Reichweite.\r\n\r\nLieferumfang:\r\n\r\n2 Wurfarmendkappen aus Polymer\r\n1 Sehne\r\n1 Spannhilfe', 45.00, NULL, 1, 0.00, '', 'https://web.lweb.ch/usa/img/armbrust_zubehor/0000419', 'Steambow', '2026-04-30 15:17:56', '2026-04-30 15:17:56', 'armbrust-zubehoer', 0, NULL, NULL, NULL, 'Steambow', 0.500),
(420, '0000420', 'AR-6 Stinger II – Wurfarm „PRO“ (90 lbs)', 'Unser neuer Glas-/Carbon-Wurfarm AR-6 Stinger II „PRO“ liefert deutlich mehr kinetische Energie als der Standardbogen der AR-6 Stinger II.\r\n\r\nHinweis:\r\nDas Zuggewicht, in diesem Fall 90 lbs, ist kein ausreichender Indikator für die Leistungsfähigkeit des Bogens einer Armbrust!\r\n\r\nViele Faktoren, wie z.B. die Länge der Beschleunigungsstrecke, die Effizienz des Bogens, die Federkennlinie des Bogens, das Gewicht des Pfeils, das Gewicht der Sehne und einiges mehr haben Auswirkungen auf die Energie, die der Pfeil beim Abschuss übertragen bekommt.\r\n\r\nJe nachdem wie schwer der Pfeil ist und wie oft die Sehne eingedreht wird (das verkürzt die Sehne), liefert dieser Bogen auf der AR-6 Stinger II zwischen 18 – 21 Joule an kinetischer Energie.\r\n\r\nAchtung:\r\nDer “PRO” Wurfarm mit 90 lbs ist nicht für alltägliche Trainingszwecke geeignet!\r\nVielmehr handelt es sich um einen Wurfarm, der für spezielle Bereiche entwickelt wurde, so z.B. für die Jagd, für besonders hohe Reichweiten oder für die Verteidigung.\r\nNutze mit dem 90 lbs Bogen ausschließlich geeignete und ausreichend schwere (>10 Gramm/154 grains) Pfeile, wie unsere Jagd- und Bodkinpfeile.\r\n\r\nUnsere blauen Übungspfeile sind aufgrund des Gewichts nur eingeschränkt für den “PRO” Wurfarm geeignet und belasten Sehne und Wurfarmendkappen. Zu leichte Pfeile belasten das Material ähnlich wie ein Trockenschuss und führen schnell zu Rissen in den Endkappen.\r\nBeachte bitte außerdem, dass der “PRO” Wurfarm auch bei bestimmungsgemäßem Gebrauch zu höherem Verschleiß der Sehne führt.\r\n\r\nSchäden durch Trockenschüsse, zu leichte Pfeile oder wegen fehlender Wartung sind nicht durch unsere Garantie abgedeckt!\r\n\r\nDie neuen Wurfarme der AR-6 Stinger II passen nicht auf die Vorgängerversionen der AR-6 Stinger.\r\nAußerdem ist der „PRO“ Wurfarm für die AR-6 Stinger II Compact ungeeignet, da die nötige Kraft zum Spannen direkt aufgebracht werden muss und dieser Wurfarm daher in aller Regel zu stark ist.', 64.00, NULL, 1, 0.00, '', 'https://web.lweb.ch/usa/img/armbrustzubehor/0000420', 'Steambow', '2026-04-30 15:17:56', '2026-05-10 14:09:01', 'armbrust-zubehoer', 8, NULL, NULL, NULL, 'Steambow', 0.300),
(424, '0000424', 'Schnelllader für AR-6 Stinger II (5 Pfeile)', 'Schnelllader zum raschen Befüllen des Magazins. Ausgelegt für 5 Pfeile.\r\n\r\nLieferumfang:\r\n\r\n1 Schnelllader für 5 Pfeile\r\n3 Befestigungsschnüre (blau, rot und schwarz)\r\nFarbe der Befestigungsschnur signalisiert Typ der geladenen Pfeile.\r\n\r\nPfeile sind nicht im Lieferumfang enthalten.', 26.00, NULL, 1, 0.00, '', 'https://web.lweb.ch/usa/img/armbrustzubehor/0000424', 'Steambow', '2026-04-30 15:17:56', '2026-04-30 15:17:56', 'armbrust-zubehoer', 10, NULL, NULL, NULL, 'Steambow', 0.300),
(469, '0000469', 'AR-6 Stinger II Klappschaft-Adapter', 'Adapter um die Schulterstütze der AR-6 Stinger II klappbar zu machen.', 79.00, NULL, 1, 0.00, '', 'https://web.lweb.ch/usa/img/armbrustzubehor/0000469', 'Steambow', '2026-04-30 15:17:56', '2026-05-10 14:09:01', 'armbrust-zubehoer', 1, NULL, NULL, NULL, 'Steambow', 0.300),
(471, '0000471', 'Taktischer Pfeilköcher für AR-6 Stinger II', 'Mit dem neuen taktischen Pfeilköcher lassen sich die 5er-Speedloader für die AR-6 Stinger II ideal tragen, lagern und gefahrlos transportieren.\r\n\r\nDer Pfeilköcher ist für das MOLLE-System ausgelegt und lässt sich daher auf vielen Rucksäcken, Westen oder ähnlichen Kleidungsstücken stabil anbringen. Außerdem lässt sich der Speedloader, in verschiedenen Winkeln, auch an einem Gürtel oder am Hosenbund tragen. Durch die mitgelieferte Picatinny-Halterung kannst du den Pfeilköcher überdies direkt an der Stinger II befestigen, so hast du weitere Pfeile stets griffbereit.\r\n\r\n \r\n\r\nAchtung: Für die seitliche Befestigung an der Stinger II benötigst du überdies die optionale seitliche Picatinnyschiene (Artikel Nr.: 0000472)Lieferumfang:\r\n\r\n1 Taktischer Pfeilköcher für AR-6 Stinger II\r\n1 Schnelllader V2\r\n1 Gürtelclip\r\n1 Picatinny-Montageblock\r\nbenötigte Schrauben und Montagematerial', 39.00, NULL, 1, 0.00, '', 'https://web.lweb.ch/usa/img/armbrustzubehor/0000471', 'Steambow', '2026-04-30 15:17:56', '2026-04-30 15:17:56', 'armbrust-zubehoer', 4, NULL, NULL, NULL, 'Steambow', 0.300),
(507, '507', 'Multifunktions Räucherofen mit Fenster u. Zubehör aus 1.4016 Edelstahl', 'Multifunktionsräucherofen mit den Abmessungen: 80 x 40 x 27 cm\r\n\r\nRäucherschrank zum Senkrecht- und Waagerecht Räuchern, incl. \r\n2 x Fischkorb\r\n1 x Flachrost\r\n1 x 5 Stk. S-Haken\r\n1 x 5 Stk. Haken Standard\r\n1 x Abtropfblech\r\n1 x Räuchermehlschale\r\n1 x Glutkasten\r\n1 x Bedienungsanleitung\r\n1 x SMOKI-Thermometer 0-120°C\r\n1 x 500gr. Buche fein\r\n\r\nDer Ofen ist im Bereich der Scheibe mit einem hitzebeständigem Isolierband versehen, um Glasbruch unter Hitzespannung zu vermeiden.', 199.00, NULL, 1, 0.00, '', 'https://web.lweb.ch/usa/img/rauch_grill/507', 'Smoki', '2026-04-30 15:19:15', '2026-04-30 15:19:15', 'rauch-grill', 0, NULL, NULL, NULL, 'Smoki', 99.999),
(533, '0000533', 'AR-6 Stinger II Tuning Abzug', 'Der Tuning Abzug verringert das Abzugsgewicht deutlich (mit dem 90 lbs. Wurfarm um fast 50%) und hilft dir, genauer zu treffen. Insbesondere wenn du sportlich schießen möchtest, bietet das große Vorteile. Der Abzug hat ein gleichmäßiges Abzugsgewicht (beim Standard Abzug steigt das Abzugsgewicht an bis der Schuss bricht) und ist konstanter und weicher im Abzugsverhalten. Ebenso hilft es dir Abzugsfehler schnell und mit weniger Trainingsaufwand in den Griff zu bekommen.\r\n\r\nLieferumfang:\r\n\r\n1 schwarzer Abzug\r\n1 roter Abzug\r\n1 Zahnstange\r\n1 Feder\r\n1 Stift', 29.00, NULL, 1, 0.00, '', 'https://web.lweb.ch/usa/img/armbrust_zubehor/0000533', 'Steambow', '2026-04-30 15:17:56', '2026-05-10 14:09:01', 'armbrust-zubehoer', 1, NULL, NULL, NULL, 'Steambow', 0.200),
(539, '0000539', 'AR-6 Stinger II – Magazindeckel für Zielfernrohrmontage inkl. Feder', 'Magazindeckel für die AR-6 Stinger II mit Picatinny-Schiene für die Montage eines Visiers, wie beispielsweise unser Zielfernrohr.', 19.00, NULL, 1, 0.00, '', 'https://web.lweb.ch/usa/img/armbrustzubehor/0000539', 'Steambow', '2026-04-30 15:17:56', '2026-04-30 15:17:56', 'armbrust-zubehoer', 4, NULL, NULL, NULL, 'Steambow', 0.300),
(541, '0000541', 'AR-6 Stinger II Upgrade-Kit “Schnellwechsel-Wurfarme”', 'Das AR-6 Stinger II Upgrade-Kit “Schnellwechsel-Wurfarme” ermöglicht dir den schnellen und unkomplizierten Wechsel des Wurfarms deiner AR-6 Stinger II. Damit passt die AR-6 Stinger II in fast jeden Rucksack und ist in Sekundenschnelle aufgebaut und feuerbereit.', 45.00, NULL, 1, 0.00, '', 'https://web.lweb.ch/usa/img/armbrust_zubehor/0000541', 'Steambow', '2026-04-30 15:17:56', '2026-04-30 15:17:56', 'armbrust-zubehoer', 0, NULL, NULL, NULL, 'Steambow', 0.500),
(621, '0000621', 'AR-6 Stinger II Tactical & Compact: Rändelschraube für Magazin', 'Rändelschraube für die schnelle und werkzeugfreie (De-)Montage des Magazins deiner AR-6 Stinger II Tactical oder Compact.', 4.00, NULL, 1, 0.00, '', 'https://web.lweb.ch/usa/img/armbrust_zubehor/0000621', 'Steambow', '2026-04-30 15:17:56', '2026-05-04 15:02:32', 'armbrust-zubehoer', 1, NULL, NULL, NULL, 'Steambow', 0.100),
(950, '950', 'Gulaschkanone aus Edelstahl mit emailliertem Gulaschkessel für ca. 9l', 'Höhe 48 cm (mit Füßen und Rauchrohr ca. 120 cm)\r\nBreite 48 cm\r\nTiefe 37 cm\r\nKorpus aus Edelstahl\r\nKochkessel emailiert, mit Deckel und Tragegriff\r\nVolumen ca. 9 Liter\r\nRauchrohr und Bogen aus Schwarzblech\r\nAschekasten\r\nseitliche Tragegriffe\r\nZum Kochen einer Suppe oder Erhitzen eines leckeren Glühweins ebenso geeignet wie zur Herstellung von Fischfutter (Boilies)!\r\n\r\nEinfach zu Montieren und daher auch portabel.', 119.00, NULL, 1, 0.00, '', 'https://web.lweb.ch/usa/img/rauch_grill/950', 'Smoki', '2026-04-30 15:19:15', '2026-04-30 15:19:15', 'rauch-grill', 0, NULL, NULL, NULL, 'Smoki', 99.999),
(951, '951', 'Bratblech / Maroniblech für Gulaschkanone', 'Erweitern Sie Ihre Gulaschkanone mit diesem Blech zum Braten und Warmhalten. Passend für Modell 950.', 19.00, NULL, 1, 0.00, '', 'https://web.lweb.ch/usa/img/rauch_grill/951', 'Smoki', '2026-04-30 15:19:15', '2026-04-30 15:19:15', 'rauch-grill', 2, NULL, NULL, NULL, 'Smoki', 0.500),
(952, '952', 'Turbinengrill', 'GARTENGRILL TURBINE DREHBAR\r\n\r\nKosten Sie ein ausgezeichnetes Hähnchen vom Grill mit knuspriger, wohlriechender Haut.\r\n\r\nIm Gartengrill können auch auf „Standard“-Haken senkrecht aufgehängte Fische gegrillt werden.\r\n\r\nDarüber hinaus können im Gartengrill auch Fleischstücke an Spießen gegrillt werden.\r\n\r\nTechnische Daten:\r\n\r\nAußendurchmesser: 320 mm\r\n\r\nHöhe: 450 mm\r\n\r\nGewicht: ca 4,5 kg\r\n\r\nBrennstoff: Holzkohlenpellets, Holzbriketts\r\n\r\nEinzelteile: Nirosta-Stahl-Gehäuse, Heizmantel, Spieß, Flügelrad', 109.00, NULL, 1, 0.00, '', 'https://web.lweb.ch/usa/img/rauch_grill/952', 'Smoki', '2026-04-30 15:19:15', '2026-04-30 15:19:15', 'rauch-grill', 1, NULL, NULL, NULL, 'Smoki', 10.000),
(953, '953', 'Kochtopf, emailliert', 'auch als Ersatz für unsere Gulaschkanone\r\nca. 9,3 Liter Volumen\r\nmit Deckel', 39.00, NULL, 1, 0.00, '', 'https://web.lweb.ch/usa/img/rauch_grill/953', 'Smoki', '2026-04-30 15:19:15', '2026-04-30 15:19:15', 'rauch-grill', 0, NULL, NULL, NULL, 'Smoki', 2.000),
(981, '981', 'Unterbau /Ständer aus V2A Edelstahl für Räucherofen', 'für eine optimale Arbeitshöhe\r\nideal für die Unterbringung einer Gasflasche\r\naus Edelstahl V2A 1.4301\r\nEs können Öfen mit einer Grundfläche bis zu 47x35cm darauf gestellt werden.\r\n\r\nLieferumfang ist der Unterbau\r\n\r\nAußenmaße B=410; T=340; H=600mm\r\nInnenmaße B= 407; T=335; H=567mm', 129.00, NULL, 1, 0.00, '', 'https://web.lweb.ch/usa/img/rauch_grill/981', 'Smoki', '2026-04-30 15:19:15', '2026-04-30 15:19:15', 'rauch-grill', 2, NULL, NULL, NULL, 'Smoki', 2.000),
(991, '991', 'Raucherzeuger für Smoki Räucherofen aus V2A-Edelstahl', 'Raucherzeuger zum Kalträuchern\r\n\r\nKombinieren Sie unseren Räucherofen Smoki mit diesem Raucherzeuger und Räuchern Sie problemlos kalt Fleisch.\r\n\r\nIm Raucherzeuger wird mittels Holz, Gas- oder Elektroheizung nach dem Smoki-Prinzip Rauch in der Räuchermehlschale erzeugt.\r\n\r\nAbmessung: 40x39x33cm\r\n\r\nIncl.:\r\n\r\nabziehbarem Schlüssel\r\nkomfortable Tür mit Edelstahlscharnieren und stabilem Schloss\r\nTür umlaufend stabil mehrfach gekantet\r\nAnnietstutzen montiert und mit Isolierband versehen\r\n1 m flexiblem Schlauch aus Aluminium\r\nSchubladeneinsatz für den Räucherofen Smoki mit montiertem Annietstutzen\r\nAndere Ofenmodelle können mit unseren Annietstuzen versehen werden. Damit können Sie den Raucherzeuger auch für andere Modelle nutzen, müssen allerdings ein Loch in Ihren Ofen schneiden (Durchmesser ca. 80-100mm).\r\n\r\nPhotos zeigen Anwendungsbeispiele, abgebildete Teile/Geräte nur im Lieferumfang, sofern angegeben.', 199.00, NULL, 1, 0.00, '', 'https://web.lweb.ch/usa/img/rauch_grill/991', 'Smoki', '2026-04-30 15:19:15', '2026-04-30 15:19:15', 'rauch-grill', 0, NULL, NULL, NULL, 'Smoki', 0.300),
(1003, '1003', 'Klappständer', 'für eine optimale Arbeitshöhe\r\n\r\nH52cm B 43cm T 30cm\r\n\r\nBestehend aus\r\n\r\n- 20x20mm Vierkantrohr verzinkt + Platte', 35.00, NULL, 1, 0.00, '', 'https://web.lweb.ch/usa/img/rauch_grill/1003', 'Smoki', '2026-04-30 15:19:15', '2026-04-30 15:19:15', 'rauch-grill', 2, NULL, NULL, NULL, 'Smoki', 10.000),
(1006, '1006', 'Fischkorb / Fischrost 34x25cm aus 1.4301 V2A-Edelstahl', 'aus Edelstahl\r\nspülmaschinenfestaus vollautomatischer Fertigung\r\n                                                                                                                                                                                                                                                                Made in Germany', 19.00, NULL, 1, 0.00, '', 'https://web.lweb.ch/usa/img/rauch_grill/1006', 'Smoki', '2026-04-30 15:19:15', '2026-04-30 15:19:15', 'rauch-grill', 5, NULL, NULL, NULL, 'Smoki', 0.300),
(1010, '1010', 'Flachrost 34x25 cm aus 1.4301 V2A-Edelstahl', 'Die Abmessungen betragen 34x25cm, damit passt das Flachrost in alle gängigen Modelle. Messen Sie einfach in Ihrem Ofen nach, ob das Maß ausreicht.\r\n\r\nFür diverse andere Modelle haben wir ebenfalls die passenden Roste, geben Sie uns einfach Ihre Maße durch, mail an: smoki-shop@smokiofen.de\r\n\r\nRoste sind aus Edelstahl und spülmaschinenfest.\r\n\r\nMade in Germany', 19.00, NULL, 1, 0.00, '', 'https://web.lweb.ch/usa/img/rauch_grill/1010', 'Smoki', '2026-04-30 15:19:15', '2026-04-30 15:19:15', 'rauch-grill', 23, NULL, NULL, NULL, 'Smoki', 0.300),
(1032, '1032', 'Räucherofen 100x39x33cm mit Scheibe aus Cr-Edelstahl 1.4016', 'Aus poliertem 1.4016 Chrom-Edelstahl mit Scheibe\r\n\r\nMaße: H 100 cm, B 39 cm, T 33 cm.\r\n\r\nAuf dem Ofen und an der Kohleschublade befindet sich je eine', 299.00, '69f861ba89558_1777885626_0.jpg', 1, 0.00, '', 'https://web.lweb.ch/usa/img/rauch_grill/1032', 'Smoki', '2026-04-30 15:19:15', '2026-05-04 09:07:06', 'rauch-grill', 0, NULL, NULL, NULL, 'Smoki', 99.999),
(1178, '1178', 'Bravo Two Classic BK - SET', 'Anlässlich des 15-jährigen Firmenjubiläums von Pohl Force werden die beliebten Klappmesser-Modelle Bravo One und Two Gen. 1 neu aufgelegt.\r\n\r\nIhre Grö', 189.00, '69f5f1695a4ab_1777725801_0.jpg', 1, 0.00, '', 'https://web.lweb.ch/usa/img/messer/1178', 'PohlForce', '2026-04-30 15:18:29', '2026-05-05 08:25:19', 'klappmesser', 0, NULL, NULL, NULL, 'PohlForce', 0.500),
(1179, '1179', 'Bravo Two Classic FDE - SET', 'Anlässlich des 15-jährigen Firmenjubiläums von Pohl Force werden die beliebten Klappmesser-Modelle Bravo One und Two Gen. 1 neu aufgelegt.\r\n\r\nIhre Grö', 189.00, '69f5f189077b7_1777725833_0.jpg', 1, 0.00, '', 'https://web.lweb.ch/usa/img/messer/1179', 'PohlForce', '2026-04-30 15:18:29', '2026-05-05 08:25:25', 'klappmesser', 0, NULL, NULL, NULL, 'PohlForce', 0.500),
(1222, '1222', 'Räucherofen 120x39x33cm aus V2A-Edelstahl mit Sichtfenster', 'SMOKI-Räuchertechnik: Handgefertigte Qualität in Serie\r\n\r\nHochwertige Ware aus V2A, Werkstoff 1.4301\r\n\r\n\r\nMaße: H 120 cm, B 39 cm, T 33 cm\r\n\r\nDer Ofen ist standardmäßig ausgestattet mit\r\n\r\nregelbaren Rauchabzügen, bzw. Belüftungsklappen an Himmel und Kohleschublade\r\nkomplett schließender Glutkasten, damit können Sie auch nur mit Holz ohne Räuchermehl räuchern\r\numlaufend gekanteter Tür\r\nstabilen Verriegelungen mit abziehbarem Schlüssel (Kindersicherung!)\r\ngelochtem Trennblech zwischen Brenn- und Räucherraum\r\n10 Einschubebenen für Haken, Roste oder Körbe\r\nsie können Heiß- und Kalträuchern.\r\nSie können direkt unsere Elektroheizung oder unseren Gasbrenner 4,2kW in den Ofen ohne Umbauten einsetzen\r\n \r\nInklusive\r\n\r\nKohleschublade aus Schwarzblech mit Edelstahlblende\r\nRäuchermehlschale\r\nFettauffangblech\r\nMetall-Thermometer 0-120°C\r\n4 Stk. Winkelbleche zum Einhängen Ihrer Räucherhaken\r\n2 verchromte Tragegriffe\r\nausführlicher Bedienungsanleitung\r\nWeiteres Zubehör auf Abbildung kann extra bestellt werden und ist nur im Lieferumfang emthalten, sofern angegeben.', 650.00, NULL, 1, 0.00, '', 'https://web.lweb.ch/usa/img/rauch_grill/1222', 'Smoki', '2026-04-30 15:19:15', '2026-04-30 15:19:15', 'rauch-grill', 1, NULL, NULL, NULL, 'Smoki', 99.999),
(1223, '1223', 'ISOLIERTER Räucherofen 120x39x33cm Smoki aus V2A-Edelstahl', 'Aus 1.4301 V2A-EDELSTAHL in doppelwandiger Ausführung mit Rundum-Isolierung.\r\n\r\nMaße: H 120 cm B 39 cm T 33 cm.\r\n\r\nZwischen Brennraum und Räucherraum befindet sich ein gelochtes Trennblech, Sie können daher mit den Smokiöfen auch ausschließlich mit Holz gleichzeitig Heizen und Räuchern!\r\n\r\nDer Ofen kann hängend oder liegend in 10 Ebenen mit Fisch, Fleich oder Wurst bestückt werden.\r\n\r\nInklusive\r\n\r\nLüftungsschieber an der Kohleschublade\r\n20mm Rookwool Isolierung\r\nDachdurchführung mit Drosselklappe\r\nKohleschublade aus verzugsreduzierendem Schwarzblech mit Edelstahlblende\r\nRäuchermehlschale\r\nFettauffangblech\r\nThermometer 0-120°C\r\n4 Stk. Einhängestangen für Räucherhaken\r\nseitliche verchromte Tragegriffe\r\nAusführlicher Bedienungsanleitung mit Rezeptideen\r\nEinsatz von Elektroheizung oder Gaskocher möglich\r\nAusstattungen auf Photos nur im Lieferumfang, sofern angegeben.\r\n\r\nPhoto zeigt baugleiches, aber größeres Modell mit 150cm Höhe.', 850.00, NULL, 1, 0.00, '', 'https://web.lweb.ch/usa/img/rauch_grill/1223', 'Smoki', '2026-04-30 15:19:15', '2026-04-30 15:19:15', 'rauch-grill', 0, NULL, NULL, NULL, 'Smoki', 99.999),
(1522, '1522', 'Räucherofen Smoki 150x39x33 aus V2A-Edelstahl mit Sichtfenster', 'SMOKI-Räuchertechnik: Handgefertigte Qualität in Serie\r\n\r\nMade in Germany aus 1.4301 (V2A) Edelstahl.\r\n\r\nSerienmäßig ausgerüstet mit:\r\n\r\nKohleschublade aus verzugsreduzierendem Schwarzblech mit Edelstahlblende\r\nRäuchermehlschale\r\nRegelbarem Rauchabzug\r\nFettauffangblech\r\nThermometer\r\n4 Stäbe zum Einhängen Ihrer Räucherhaken\r\n2 Tragegriffe\r\nAuf dem Ofen und an der Kohleschublade befinden sich regelbare Rauchabzüge, bzw. Belüftungsklappen.\r\nDer Ofen hat stabile Verriegelungen mit abziehbarem Schlüssel (Kindersicherung!).\r\nAn den Seiten befinden sich feste verchromte Tragegriffe. Der Brennraum und Räucherraum sind getrennt, das Trennblech ist gelocht.\r\nOptional können unsere Fischkörbe und Fischroste verwendet werden, es sind 11 Einschubebenen montiert.\r\nOptional kann unser Brenner mit 4,2kW oder unsere Elektroheizung eingesetzt werden\r\nDer Ofen kann in 9 Lagen mit Fisch, Fleisch oder Wurst bestückt werden. Zusätzlich kann hängend geräuchert werden.\r\n\r\nZusatzausstattung auf den Photos nur im Lieferumfang, sofern angegeben. Es wird das Modell mit Scheibe geliefert.', 699.00, NULL, 1, 0.00, '', 'https://web.lweb.ch/usa/img/rauch_grill/1522', 'Smoki', '2026-04-30 15:19:15', '2026-04-30 15:19:15', 'rauch-grill', 1, NULL, NULL, NULL, 'Smoki', 99.999),
(1523, '1523', 'ISOLIERTER Räucherofen 150x39x33cm aus 1.4301 V2A-Edelstahl', '1.4301 V2A-EDELSTAHL in doppelwandiger Ausführung mit Rundum-Isolierung.\r\n\r\nMaße: H 150 cm B 39 cm T 33 cm.\r\n\r\nan der Kohleschublade befindet sich eine regelbare Belüftungsklappe.\r\nDer Ofen hat stabile Spannverriegelungen\r\nZwischen Brennraum und Räucherraum befindet sich ein gelochtes Trennblech, Sie können daher mit den Smokiöfen auch ausschließlich mit Holz gleichzeitig Heizen und Räuchern!\r\nDer Ofen kann hängend an Haken oder in 12 weiteren Ebenen mit Fisch, Fleich oder Wurst bestückt werden.\r\nGriffe sind komplett montiert\r\nSie können Heiß- und Kalträuchern\r\noptinal können Sie den Ofen mit unserer Elektroheizung (Art. 103) oder Gasbrenner (Art. 104) ausrüsten.\r\nInklusive\r\n\r\nLüftungsschieber an der Kohleschublade\r\n20mm Isolierung\r\nDachdurchführung mit Drosselklappe\r\nKohleschublade aus verzugsreduzierendem Schwarzblech mit Edelstahlblende\r\nRäuchermehlschale\r\nFettauffangblech\r\nThermometer 0-120°C\r\n4 Stk. Einhängestangen für Räucherhaken\r\nBedienungsanleitung mit Rezeptideen\r\nAusstattungen auf den Photos sind nur im Lieferumfang, sofern in dieser Beschreibung aufgelistet.', 999.00, NULL, 1, 0.00, '', 'https://web.lweb.ch/usa/img/rauch_grill/1523', 'Smoki', '2026-04-30 15:19:15', '2026-04-30 15:19:15', 'rauch-grill', 0, NULL, NULL, NULL, 'Smoki', 99.999),
(2448, '2448', 'Quebec Two - Special Forces (Field)', 'Das neue Quebec Two - die nächste Evolutionsstufe des klassischen Einsatzmessers der Pohl Force Quebec-Serie! \r\n\r\nMit der „Special Forces“ Serie auf B', 279.00, NULL, 1, 0.00, '', 'https://web.lweb.ch/usa/img/messer/2448', 'PohlForce', '2026-04-30 15:18:29', '2026-05-05 09:03:34', 'feste-klinge', 1, NULL, NULL, NULL, 'PohlForce', 0.500),
(4416, '4416', 'Multi TacKnife Black', 'Multi Tac steht für eine neue Generation von Multifunktionsmessern - eine Kombination von Tactical Messer und Tool. Die matt schwarz gehaltene Einhandklinge mit partiellem Wellenschliff hat eine Liner Lock-Verriegelung. Im Griff des Tactical Messers befindet sich das Multifunktionswerkzeug bestehend aus Flaschenöffner, Dosenöffner, Schraubendreher sowie einem ausschwenkbaren Bithalter.', 66.00, NULL, 1, 0.00, '', 'https://web.lweb.ch/usa/img/messer/4416', 'Walther', '2026-04-30 15:18:29', '2026-05-05 09:00:36', 'klappmesser', 2, NULL, NULL, NULL, 'Airsoft', 0.500),
