(336511, '336511', 'Linder Black Line 2', 'Linder Black Line 2\r\n\r\nWer auf optimierte Balance und Griffigkeit und damit auf ein Höchstmaß an Praxistauglichkeit Wert legt kommt an dieser Modellre', 35.00, NULL, 1, 0.00, '', 'https://web.lweb.ch/usa/img/messer/336511', 'Linder', '2026-04-30 15:18:29', '2026-05-05 08:37:10', 'klappmesser', 0, NULL, NULL, NULL, 'Linder', 0.500),
