(426227, '426227', 'Linder Scorpion TH', '„Scorpion“-Wurfbeil rostfrei. Klinge schwarz beschichtet, mit Kordel umwickelter Griff. Gesamtlänge 27 cm. Gewicht 248 g. In Cordura-Scheide.', 29.00, NULL, 1, 0.00, '', 'https://web.lweb.ch/usa/img/beil/426227', 'Linder', '2026-04-30 15:19:32', '2026-04-30 15:19:32', 'beil', 0, NULL, NULL, NULL, 'Linder', 1.000),
(444408, '444408', 'Linder Panda 6', 'Linder Panda 6\r\n\r\nWie bei dem bekannten Bär beschränkt sich die Farbgebung dieses Messers auf die Farben schwarz und weiß. Und die Kombination dieser', 51.00, NULL, 1, 0.00, '', 'https://web.lweb.ch/usa/img/messer/444408', 'Linder', '2026-04-30 15:18:29', '2026-05-05 08:37:21', 'feste-klinge', 0, NULL, NULL, NULL, 'Linder', 0.500);
INSERT INTO `products` (`id`, `article_number`, `name`, `description`, `price`, `image`, `heat_level`, `rating`, `badge`, `image_url`, `origin`, `created_at`, `updated_at`, `category`, `stock`, `image2`, `image3`, `image4`, `supplier`, `weight_kg`) VALUES
(512012, '512012', 'Bowiemesser-Kombi', 'Beschreibung\r\n\r\nBowiemesser-Kombi\r\n\r\nBowiemesser-Kombi mit Klingen aus rostfreiem 440 Stahl. Griffe vergoldet mit Pakkaholzschalen. Beide Messer in einer Lederscheide. Klingenlängen 21 cm bzw. 13 cm.', 149.00, NULL, 1, 0.00, '', 'https://web.lweb.ch/usa/img/messer/512012', 'Linder', '2026-04-30 15:18:29', '2026-05-05 08:21:31', 'feste-klinge', 0, NULL, NULL, NULL, 'Linder', 0.500),
(831012, '831012', 'Eickhorn Pacific RESCUE TANTO 1', 'Gestrahlte Klinge aus 440A, rostfrei. Griff aus gestrahltem Edelstahl mit schwarzen G-10 Einlagen. Gurtschneider und Glasbrecher sind in den Griff int', 41.00, NULL, 1, 0.00, '', 'https://web.lweb.ch/usa/img/messer/831012', 'Eickhorn', '2026-04-30 15:18:29', '2026-05-05 08:29:51', 'klappmesser', 0, NULL, NULL, NULL, 'Linder', 0.500),
(841750, '841750', 'WETTERHALL 1,6 Wurfaxt HB', 'WETTERHALL 1,6 Wurfaxt HB\r\nDiese Art von Doppel-Bit-Äxten wurde ursprünglich von Holzfällern benutzt, die davon profitierten, jederzeit eine scharfe Axt griffbereit zu haben. So wurde eine Seite für raue Arbeiten und die andere für Feinarbeiten verwendet. Heute wird die Axt hauptsächlich in Wettbewerben unter Enthusiasten als Wurfaxt verwendet. Sie wurde nach dem Schmied Wetterhall be-nannt, der länger als jeder andere in Hults Bruk gearbeitet hat. Wie bei allen Hulta-fors Äxten ist auch die Wetterhall Wurfaxt handgeschmiedet und aus schwedischem Qualitätsstahl hergestellt. Als Teil des Kopfschmiedeprozesses wurde der Stah-laxtkopf 40–60 Mal geschlagen, wodurch die Dichte erhöht und die daraus resultie-rende Haltbarkeit verlängert wurde.\r\n\r\nHERVORRAGENDE WURFAXT\r\nGESAMTGEWICHT: 2280 G\r\nKOPFGEWICHT: 1600 G\r\nGRIFFLÄNGE: 760 MM /30”\r\nHOLZGRIFF AUS AMERIK ANISCHER HICKORY,\r\nMIT LEINÖL BEHANDELT\r\nKANTE IST GESCHLIFFEN, POLIERT UND GEBRAUCHSFERTIG\r\nINKLUSIVE LEDER SCHNEIDSCHUTZ\r\nHANDGESCHMIEDET IN SCHWEDEN', 499.00, NULL, 1, 0.00, '', 'https://web.lweb.ch/usa/img/beil/841750', 'Hultafors', '2026-04-30 15:19:32', '2026-04-30 15:19:32', 'beil', 1, NULL, NULL, NULL, 'Naturzone', 2.200),
(2106612, '2106612', 'SYTONG HT-66 / NV850 GERMAN-EDITION mit 12 mm Objektiv', 'SYTONG HT-66 / NV850 GERMAN-EDITION mit 12 mm Objektiv / ohne zuschaltbaren Absehen und Richt-Zielpunktlaser ( in Deutschland durch das BKA-Waffenbehörde erlaubt ) Art. Nr. Art. Nr. 2106612\r\nAlle SYTONG NIGHT VISION HT-66 und HT-660 GERMAN EDITION GERÄTE haben immer die aktuellste Geräte SOFWARE-VERSION im Gerät Installiert.\r\nWICHTIGER SOFTWARE HINWEIS: \r\nAb Sofort sind alle  SYTONG HT-66 GERMAN EDITION derGENERATION II. mit neuer SOFTWARE und  zusätzlich mit dem begehrten NACHTSICHT grün Modus ausgestattet.\r\n\r\nPRODUKTINFOMATION\r\n\r\nDas neue SYTONG HT-66 / NV 850 , ist ein neuartige DUAL -USE -Nachssatz-Nachtsicht-Gerät für Zielfernrohre und die Geräte- Funktion ist ähnlich wie beim NV-007A , nur das SYTONG HT 66 / NV 850 hat technische Vorteile und ist eine neue Generation als DUAL – USE Gerät am Markt.\r\nBei den Geräte-abmaßen und beim Gewicht des neuen SYTONG HT-66 / NV850 sind diese gleich wie beim PARD NV-007A das gleiche gilt für das Adapter- Aufnahme Verschluss-System, also gleiche Adapteraufnahme wie beim PARD Gerät NV 007 oder NV007A.\r\nDie Adapteraufnahme-Platte am SYTONG HT -66 / NV 850 ist so aufgebaut , das auch die am Markt befindlichen PARD 007 A Adapter das bedeutet, alle Geräte Adapter für Zielfernrohre vom PARD – 007 oder 007A / NV 850 sind passgenau am SYTONG HT -66 und passen und umgekehrt genauso am PARD -007 oder 007A/ NV850.\r\n\r\nSYTONG HT-66 / NV 850 GERÄTE-VORTEILE gegenüber Geräte Mitbewerber am Markt\r\n\r\nSYTONG hat am HT-66 einen SONY CMOS-Sensor verbaut, es ist das neue HIGH LIGHT am neuen SYTONG HT-66 DUAL USE GERÄT und bietet folgende Vorteile gegenüber Mitbewerber Geräten ( wie zum Beispiel beim PARD007 / 007A ) am Markt.\r\nEin Saubere und wenig verpixelte Bild-Wiedergabe,mit einer höheren Reichweite\r\nKeine Bild-Verzögerungen beim Schwenken des SYTONG HT-66\r\nEin besserer verbauter IR-STRAHLER trotz gleicher technischer Parameter des IR -STRAHLER von NV 850\r\nDer IR-STRAHLER am HT -66 ist stärker fokussierbar, dadurch erhöht sich auch die Reichweite vom IR- Lichkegel.\r\nDer verbaute SONY CMOS Sensor kann das Bild viel schneller her runter regulieren, sobald der IR-STRAHLER betätigt und eingeschaltet wird, hierdurch erfolgt auch keine Augen- Überblendung.\r\nEs bleibt auch eine Augen- Überblendungen bei eingeschalteten und fokussierten IR-LICHT aus , dies Umstand macht es auch beim Einsatz des SYTONG HT-66 im Waldbestand angenehmer\r\nEin weitere Vorteil bietet der HT- 66 OLED Bildschirm, dieser lässt sich per Knopfdruck bis auf 10% her herunter-dimmen, also von „extra Dunkel “l bis „extra Hell“. (Bei PARD Geräten geht das nur über das Menüführung und dann leider nur bis auf maximal 50%)\r\nWeiter hat das SYTONG einen Integrierten Gyrometer-Sensor mit einer Dreh- und Neigungswinkelanzeige wird auf dem OLED- DISPLAY angezeigt.\r\nFarbe am OLED DISPLAY umschaltbar , bei TAG farbige Bildanzeige, bei Nacht umschaltbar auf schwarz - weiß Bildanzeige.\r\nBeim SYTONG HT- 66 sind alle Gerätetastaturen lautlos bedienbar\r\nDie Schussfestigkeit liegt beim SYTONG HT-66 bis zu 6000 Joule , getestet mit einen Kaliber von 9,3 mm und 300 Win Mag, man kann eigentlich auch bei ca. 7000 Joule anknüpfen.\r\nBeim SYTONG HT-66 hat der Hersteller selbst schon einen eigene Geräte App für eine Livebild-Übertragung mit direkten Zugriff auf bereits früher gespeicherte Fotos und Videos, die man direkt auf das Smartphone her runter laden kann.\r\nEinen weiteren Vorteil bieten die HT-66 Gerätetastaturen ( HT-66 Gerätebedienknöpfe) diese wurden von vornherein besser und platzierter am SYTONG HT-66 angeordnet was die Bedienung des HT-66 vereinfacht, und das vor allem auch im Handbetrieb des HT-66.\r\nDas wechseln der SD Karte am SYTONG HT-66 lässt sich viel einfacher wechseln, als bei Mitbewerber Geräten wie PARD\r\nDas SYTONG HT-66 besitzt einen USB-C Anschluss\r\nZum Gewicht des HT-66 es wiegt nur 250g\r\nBeim SYTONG HT-66 handelt es sich um ein DUAL-USE Nachsatz-Gerät , es verändert nicht bei einer Montage am ZF die Treffpunkt-Lage des Zielfernrohres, daher muss das HT-66 nicht eingeschossen werden.\r\nDas Anbringung des HT-66 am Okular des ZF hat gegenüber der Anbringung auf dem Objektiv des ZF einen besonderen Vorteil, denn bei letzterer würden die beschichteten Linsen der Optik für mehr Transmission-Verlust sorgen. So aber ist das Wild auch bei schlechten Sichtverhältnissen gut zu erkennen und anzusprechen.\r\nDank des Dioptrien-Ausgleichs beim HT-66 ist das SYTONG HT-66 auch für Brillenträger geeignet, Schießen ohne Brille möglich\r\nDas HT-66 besitzt ein fokussierbares 16-mm-Objektiv und sorgt somit für gestochen scharfe Bilder auf unterschiedlicher Distanzen\r\nSYTONG HT-66 ist für den Einsatz zu Wildbeobachtung etc. bei Tag und Nacht geeignet\r\nDank Video- und Foto-Aufnahmemöglichkeiten können Sie Ihre nächtlichen Wildbeobachtungen oder Jagdmomente zum späteren Anschauen dokumentieren und auf der 32 GB Micro-SD-Karte speichern, diese ist aber leider nicht im Lieferumfang enthalten und muss als Zubehör zugekauft werden\r\nLive-Bild-Übertragung mit Ihrem Endgerät durch Verbindung mit WLAN möglich – Anzeigen und Speichern der Live-Aufnahme auf Telefon oder Tablett erfolgt über eine spezielle App (IOS- und Androide-kompatibel).\r\nEs ist beim HT-66 kein zusätzlicher IR-STRAHLER nötig, der bereits integrierte, in 3 Stufen einstellbare, fokussierbare IR-STRAHLER bietet eine klare Sicht von 240 - 400 m möglich.\r\nDank des mitgelieferten Okular-Werksadapters von 45 mm , lässt sich das Gerät HT-66 über einen Bajonettverschluss in Sekundenschnelle durch eine Handumdrehung schussfest am Zielfernrohr montieren und demontieren. Werks-Adaptergrößen von Größer 38,8- mm - 48 mm jederzeit verwendbar.\r\n\r\nNEU: - alle SYTONG HT -66 und HT-660 GERMAN EDITION GERÄTE haben eine BILD in BILD Funktion installiert\r\nDie Vorteile eine Direkt-Kaufs zu einem SYTONG HT-66 bei uns sind:\r\n\r\nWerksgarantie von 2 Jahren für alle elektronischen Teile an SYTONG GERÄTE PRODUKTEN\r\nHinweis : Nicht in der Werksgarantie sind eingeschlossen, sind unsachgemäße Behandlung der SYTONG Geräte , Beschädigung durch äußere Einflüsse, Verlust von Geräteteilen etc.\r\nServiceleistungen an SYTONG GERÄTEN direkt bei uns im Hause\r\nErsatzteilkauf von SYTONG Gerätezubehörteile\r\nUmfangreiches Original Zubehör für SYTONG Geräte\r\nGeräte - Adapter Kauf direkt bei uns als Hersteller von Geräte - Adaptern und Zubehör\r\n\r\nIm Lieferumfang eines SYTONG HT-66 GERMAN-EDITION sind enthalten :\r\n\r\n1 Stück SYTONG HT-66 / NV 850 DUAL- USE mit 12 mm Objektiv und OLED Display\r\n1 Stück ALU - Werksadapter in Größe 45,0 mm ( Hinweis bei Bedarf Werks- Adapter auch austauschbar ) also in jeder bei uns am Lager vorrätiger Adaptergröße )\r\n1 Stück Stahl- Schnellverschluss – Schraube für ALU- Werksadapter geeignet\r\n1 Stück SYTONG 18650-Li-Ion Standard-Akku 3200 mAh\r\n1 Stück XSTAR USB-Ladegerät mit Ladestands-Anzeige für 18650-Li-Ion Akkus\r\n2 Stück Dichtungsringe für Geräte Bajonett-Aufnahme und Geräte Batterie / Akkufach Deckel\r\n1 Stück Ausgleichsklebeband für Okular (für Durchmesser Anpassung ADAPTER und Schutz vor Kratzern am ZF.\r\n1 Stück HT-66 Baumwoll- Geräte Aufbewahrungsbeutel\r\n1 Stück USB-Ladekabel / Datenkabel\r\n1 Satz Inbusschlüssel für Adapter-Montage etc.\r\n1 Stück Reinigungstuch\r\n1 Stück Stativ-Adapter\r\n1 Stück Stahl-Schnellverschluss-Schraube für Standard -Adapter\r\nHT-66 Geräte - Bedienungsanleitung in deutscher und englischer Sprache\r\nGarantie und Service Geräte Karte\r\nOriginal Verkaufsrechnung mit 2 Jahre Gewährleistung ab Verkaufsdatum\r\n\r\nTECHNISCHE GERÄTE DATEN zum SYTONG HT-66 / NV850 DUAL- USE - OLED:\r\nRückstoßkraft (Schockfestigkeit bei Beschuss)\r\nbis ca. 6000 Joule\r\nOptische Vergrößerung\r\n2x\r\nDigitale Vergrößerung (Zoom)\r\n1x - 3,5x\r\n\r\nSony CMOS-SENSOR\r\nJa\r\nObjektiv im Ø\r\n12 mm\r\nSeh-Feld (100m)\r\nca. 32 m\r\nFokussierbereich (cm)\r\n3 - unendlich\r\nGröße LxBxH (mm)\r\n106x47x97\r\nNetto-Gewicht\r\n250 g\r\nFoto Auflösung (Pixel)\r\n2608x1944 (5 Megapixel) \r\nVideo Auflösung (Pixel)\r\n1920x1080 (Full HD)\r\nTag und Nachtsicht tauglich\r\nJa\r\nBildrate (Bilder pro Sekunde)\r\n30 fps\r\nVideo-Format\r\nMP4\r\nVideo-Typ\r\nAVI\r\nOLED Bildschirm mit Auflösung (Okular)\r\n1024x768\r\nGeeignet für Okular im Ø\r\n25,0-48,0 mm\r\nDioptrien-Verstellung möglich\r\n+5 ~ -5\r\nLeistung der integrierten IR-Lampe\r\n5 w\r\nIR- STRAHLER Wellenlänge\r\n850 nm\r\nLicht-Stufen des Infrarotstrahlers\r\n3\r\nInfrarotstrahler fokussierbar\r\nJa\r\nInfrarotstrahler Beleuchtungsreichweite\r\nca.280 m\r\nSpeicherkarte\r\nMicro-SD Max. 32 GB\r\nWLAN (WiFi)- Schnittstelle / App\r\nJa\r\nAnschlüsse\r\nUSB Typ C\r\nAkkulaufzeit ( je nach Akku-Geräteauslastung )\r\n4 - 8 Stunden \r\nAkku-Typ\r\n18650\r\nTemperaturbereich\r\n-20 °C bis +50 °C\r\nGeräte Farbe\r\nSchwarz matt\r\nLive-Bildübertragung auf Smartphone oder Tablett\r\nJa\r\nMenü in mehreren Sprachen wählbar (auch in Deutscher Sprache )\r\nJa\r\nEin Stativ-Gewinde ist im Gerät HT-66 vorhanden\r\nJa\r\nZuschaltbarer / regulierbarer roter Richtlaser\r\nNEIN nicht im Gerät vorhanden\r\nZuschaltbares Kreuz-Absehen im Gerät selbst\r\nNEIN nicht im Gerät vorhanden\r\nEs bleibt auch eine Augen- Überblendungen bei eingeschalteten und fokussierten IR-LICHT aus , dies Umstand macht es auch beim Einsatz des SYTONG HT-66 im Waldbestand angenehmer\r\nEin weitere Vorteil bietet der HT- 66 OLED Bildschirm, dieser lässt sich per Knopfdruck bis auf 10% her herunter-dimmen, also von „extra Dunkel “l bis „extra Hell“. (Bei PARD Geräten geht das nur über das Menüführung und dann leider nur bis auf maximal 50%)\r\nWeiter hat das SYTONG einen Integrierten Gyrometer-Sensor mit einer Dreh- und Neigungswinkelanzeige wird auf dem OLED- DISPLAY angezeigt.\r\nFarbe am OLED DISPLAY umschaltbar , bei TAG farbige Bildanzeige, bei Nacht umschaltbar auf schwarz - weiß Bildanzeige.\r\nBeim SYTONG HT- 66 sind alle Gerätetastaturen lautlos bedienbar\r\nDie Schussfestigkeit liegt beim SYTONG HT-66 bis zu 6000 Joule , getestet mit einen Kaliber von 9,3 mm und 300 Win Mag, man kann eigentlich auch bei ca. 7000 Joule anknüpfen.\r\nBeim SYTONG HT-66 hat der Hersteller selbst schon einen eigene Geräte App für eine Livebild-Übertragung mit direkten Zugriff auf bereits früher gespeicherte Fotos und Videos, die man direkt auf das Smartphone her runter laden kann.\r\nEinen weiteren Vorteil bieten die HT-66 Gerätetastaturen ( HT-66 Gerätebedienknöpfe) diese wurden von vornherein besser und platzierter am SYTONG HT-66 angeordnet was die Bedienung des HT-66 vereinfacht, und das vor allem auch im Handbetrieb des HT-66.\r\n\r\nDas wechseln der SD Karte am SYTONG HT-66 lässt sich viel einfacher wechseln, als bei Mitbewerber Geräten wie PARD\r\n\r\nDas SYTONG HT-66 besitzt einen USB-C Anschluss\r\n\r\nZum Gewicht des HT-66 es wiegt nur 250g\r\n\r\nBeim SYTONG HT-66 handelt es sich um ein DUAL-USE Nachsatz-Gerät , es verändert nicht bei einer Montage am ZF die Treffpunkt-Lage des Zielfernrohres, daher muss das HT-66 nicht eingeschossen werden.\r\n\r\nDas Anbringung des HT-66 am Okular des ZF hat gegenüber der Anbringung auf dem Objektiv des ZF einen besonderen Vorteil, denn bei letzterer würden die beschichteten Linsen der Optik für mehr Transmission-Verlust sorgen. So aber ist das Wild auch bei schlechten Sichtverhältnissen gut zu erkennen und anzusprechen.\r\n\r\nDank des Dioptrien-Ausgleichs beim HT-66 ist das SYTONG HT-66 auch für Brillenträger geeignet, Schießen ohne Brille möglich\r\n\r\nDas HT-66 besitzt ein fokussierbares 16-mm-Objektiv und sorgt somit für gestochen scharfe Bilder auf unterschiedlicher Distanzen\r\n\r\nSYTONG HT-66 ist für den Einsatz zu Wildbeobachtung etc. bei Tag und Nacht geeignet\r\n\r\nDank Video- und Foto-Aufnahmemöglichkeiten können Sie Ihre nächtlichen Wildbeobachtungen oder Jagdmomente zum späteren Anschauen dokumentieren un