INSERT INTO `products` (`id`, `article_number`, `name`, `description`, `price`, `image`, `heat_level`, `rating`, `badge`, `image_url`, `origin`, `created_at`, `updated_at`, `category`, `stock`, `image2`, `image3`, `image4`, `supplier`, `weight_kg`) VALUES
(662332196, 'CST-90PTH', 'Trench Hawk, Schwarz', 'Trench Hawk mit schwarzem Griff\r\n\r\nDie scharfe Schlagkante und keilförmige Spitze von Cold Steels Trench Hawk bieten eine Vielzahl von Kampfmöglichkeiten für den modernen Krieger. \r\n\r\nSein Kopf ist aus 1055er Karbonstahl gesenkgeschmiedet und differenziell gehärtet. Er wird sowohl gewaltigen Schlägen als auch hoher Beanspruchung durch intensiven Gebrauch standhalten. \r\n\r\nDer Stiel aus Polypropylen ist auch besonders schlagfest. Auch eine übertriebene Nutzung, die sogar robustes Hickoryholz brechen würde, macht ihm zunächst nichts aus. Und als zusätzlicher Vorteil kann er leicht und kostengünstig ersetzt werden: Sollte er nach regem Gebrauch doch irgendwann mal verschleißen oder brechen, sind Ersatzgriffe separat erhältlich (Bitte beachte: Jeder Griff kann und wird vorraussichtlich irgendwann brechen).\r\n\r\nUm den Träger selbst vor der Schnittkante und der gefährlich scharfen Spitze zu schützen, wird das Trench Hawk mit einer patentierten Secure-Ex™ Scheide mit ausgeklügeltem Gelenkdesign geliefert. \r\n\r\nDetails: \r\n- Trench Hawk, Schwarz \r\n- Klingenmaterial: Karbonstahl 1055, gesenkgeschmiedet \r\n- Griffmaterial: Polypropylen \r\n- Gesamtlänge: ca. 48,3 cm \r\n- Axtblattlänge: ca. 22,2 cm \r\n- Schlagkante: ca. 8,9 cm \r\n- Gewicht: ca. 822 g \r\n- Inkl. Secure-Ex™ Scheide \r\n- Cold Steel Artikelnummer: 90PTH / 90PTHZ \r\n\r\nEbenfalls erhältlich: \r\n- Trench Hawk, Flat Dark Earth (Braun): Artikelnr. CST-90PTHFZ \r\n- Trench Hawk, O.D. Green (Olivgrün): Artikelnr. CST-90PTHGZ \r\n- Ersatzgriff für Trench Hawk, Schwarz: Artikelnr. CST-H90PTH', 95.00, NULL, 1, 0.00, '', 'https://web.lweb.ch/usa/img/beil/CST-90PTH', 'Coldsteel', '2026-04-30 15:19:32', '2026-04-30 15:19:32', 'beil', 0, NULL, NULL, NULL, 'Coldsteel', 1.000),
(662378297, 'CST-92BSL', 'Baseballschläger Brooklyn Whopper', 'Brooklyn Whopper, Baseballschläger\r\n\r\nDer Brooklyn Whopper ist der größte Schläger, den Cold Steel je produziert hat. Mit seinen 96 cm erreicht der Wh', 79.00, NULL, 1, 0.00, '', 'https://web.lweb.ch/usa/img/security/CST-92BSL', 'Coldsteel', '2026-04-30 15:20:30', '2026-05-05 15:15:04', 'basebalschl-ger', 1, NULL, NULL, NULL, 'Coldsteel', 1.700),
