(662378306, 'CST-92BSU', 'Baseballschläger Brooklyn Banshee', 'Brooklyn Banshee, Baseballschläger\r\n\r\nSeit ihrer Einführung 2006 erfreuen sich Cold Steels® Baseballschläger der Brooklyn-Serie großer Beliebtheit! Di', 85.00, NULL, 1, 0.00, '', 'https://web.lweb.ch/usa/img/security/CST-92BSU', 'Coldsteel', '2026-04-30 15:20:30', '2026-05-05 15:14:26', 'basebalschl-ger', 0, NULL, NULL, NULL, 'Coldsteel', 0.900),
