(914334010, 'KBS-EX-6850', 'EXCALIBUR Matrix Grizzly 305 Mossy Oak', 'Recurve Armbrust Kit MATRIX SMF GRIZZLY von EXCALIBUR neues Modell. Geschwindigkeit: 305 fps. Eigengewicht kg: 5.5 lbs. Powerstroke: 11,5 Zoll. Gesamt', 740.00, NULL, 1, 0.00, '', 'https://web.lweb.ch/usa/img/armbrust/KBS-EX-6850', 'Excalibur', '2026-04-30 15:16:39', '2026-05-05 09:18:01', 'recurve-armbrust', 0, NULL, NULL, NULL, 'SSA', 10.000),
(929040556, 'KIC-B-1255', 'Barnett Vortex Hunter Compoundbogen,26\"-30\"/ 45-60 lbs Camo', 'BARNETT Vortex Hunter - Compoundbogen - 45-60 lbs\r\nDer neue Hunter ist der größte Bogen aus BARNETTs Vortex Reihe und damit ihr krönender Abschluss. Mehr geht nicht!\r\nMit einem einstellbaren Zuggewicht von 45-60 lbs hat der Bogen ausreichend Kraft für die schwierigsten Ziele und ist dank seiner Abmessungen immernoch einfach zu handhaben, egal ob für Jugendliche oder Erwachsene. \r\nDer Bogen ist mit geschraubten Modulen ausgestattet, die ein schnelles Einstellen des Auszugs möglich machen. Wie üblich beim Compounds, kann das Zuggewicht des Vortex Hunter über die Wurfarmschrauben justiert werden.\r\nDie Verpackung kann gleichzeitig als Tragetasche für den einfachen Transport und eine optimale Lagerung dienen.\r\nNur als Rechtshandmodell verfügbar.\r\nTechnische Daten:\r\nZuggewicht: 45-60 lbs\r\nBogenlänge: 28,5 Zoll\r\nStandhöhe: 7 Zoll\r\nAuszug: 26-30 Zoll\r\nLet Off: 60-70%\r\nBreite: 10 Zoll\r\n\r\nDas umfangreiche Set besteht aus: \r\nBogen\r\nAnbauköcher für 3 Pfeile\r\n3-Pin-Visier \r\nPfeilauflage', 399.00, NULL, 1, 0.00, '', 'https://web.lweb.ch/usa/img/pfeilbogen/KIC-B-1255', 'Barnett', '2026-04-30 15:19:51', '2026-05-05 16:02:49', 'compound-bogen', 0, NULL, NULL, NULL, 'SSA', 2.100),
(941109493, 'CST-92BSBZ', 'Baseballschläger Brooklyn Basher', 'Brooklyn Basher, Baseballschläger\r\n\r\nSeit ihrer Einführung 2006 erfreuen sich die Baseballschläger der Brooklyn-Serie von Cold Steel großer Beliebthei', 50.00, NULL, 1, 0.00, '', 'https://web.lweb.ch/usa/img/security/CST-92BSBZ', 'Coldsteel', '2026-04-30 15:20:30', '2026-05-05 15:14:33', 'basebalschl-ger', 2, NULL, NULL, NULL, 'Coldsteel', 0.900),
(956073205, 'D-015A10', 'Alu Bolzen 6.5\" gold 10er Packung', 'Alu Bolzen 6.5\" gold 10er Packung', 19.00, NULL, 1, 0.00, '', 'https://web.lweb.ch/usa/img/armbrustzubehor/D-015A10', 'Ek Archery', '2026-04-30 15:17:56', '2026-05-05 10:02:10', 'armbrustpfeile-und-bolzen', 11, NULL, NULL, NULL, 'Ek Archery', 0.300),
(964023413, 'CST-88HNHD', 'Bastarddolch mit Scheide, Begleitdolch für Anderthalbhänder', 'Bastarddolch mit Scheide, Begleitdolch für Cold Steels Anderthalbhänder\r\n\r\nFür das Bastardschwert (Art.Nr. CST-88HNH) hat Cold Steel diesen passenden Begleitdolch entwickelt: Verkleinert aber nahezuidentisch im Aussehen ist dieser Dolch als Hieb- und Stichwaffe konzipiert, aber auch stark genug, um als Defensivwaffe guteArbeit zu leisten.\r\n\r\nDer Griff ist aus Holz hergestellt und mit schwarzem Leder bezogen. Das Griffende ist mit einem wunderschönen Pfropfen-Knauf versehen.\r\n\r\nBei Verarbeitung und Materialien erfüllt jeder dieser Dolche die höchsten Qualitätsansprüche. Alle Klingen sind vollständig geschärft und kampftauglich. \r\n\r\nUm die Klinge sicher zu beherbergen, wird jeder Dolch mit einer sehr attraktiven Holzscheide mit Lederbezug und Mundblech und Ortband aus Stahl geliefert.\r\n\r\nDetails: \r\n- Material: Klinge aus 1055er Karbonstahl, Holzgriff mit Lederbezug\r\n- Gesamtlänge: ca. 49 cm\r\n- Grifflänge: ca. 16 cm\r\n- Klingenlänge: ca. 33 cm \r\n- Klingenstärke: ca. 6,35 mm \r\n- Gewicht: ca. 496 g\r\n- Inkl. einer lederbezogenen Holzscheide mit Stahlbeschlägen\r\n- Herstellernr.: 88HNHD\r\n- Eine preisgünstigere, gebläute Ausführung aus der Man at Arms-Kollektion von Cold Steel ist ebenfalls erhältlich. Product No.: CST-88HNHDM.', 299.00, NULL, 1, 0.00, '', 'https://web.lweb.ch/usa/img/messer/CST-88HNHD', 'Cold Steel', '2026-04-30 15:18:29', '2026-05-05 08:19:31', 'feste-klinge', 0, NULL, NULL, NULL, 'ColdSteel', 0.500),
