(1017916223, 'A046882', 'PSE \'COALITION\' 380fps-illuminated scope-Camo', 'Die Compoundarmbrust COALITION von PSE ARCHERY ist schnell und kompakt und mit Trockenschuss-Sicherung, Safty Trigger und Sehenstoppern ausgestattet.', 599.00, NULL, 1, 0.00, '', 'https://web.lweb.ch/usa/img/armbrust/A046882', 'PSE', '2026-04-30 15:16:39', '2026-05-05 09:18:52', 'compound-armbrust', 0, NULL, NULL, NULL, 'SSA', 10.000),
(1017918204, 'A046665', 'CENTER POINT TYRO PAKET 245FPS / 175LBS', 'Die CenterPoint® Tyro™ ist eine großartige Armbrust für traditionelle Armbrustjäger, die die Haltbarkeit und Einfachheit einer Recurve schätzen.\r\nGesc', 369.00, NULL, 1, 0.00, '', 'https://web.lweb.ch/usa/img/armbrust/A046665', 'CENTERPOINT', '2026-04-30 15:16:39', '2026-05-05 09:16:26', 'recurve-armbrust', 0, NULL, NULL, NULL, 'SSA', 10.000),
(1017918395, 'A046600', 'CENTERPOINT 400 GRAIN 20\" BOLZEN 6/PACK', 'Diese erstklassigen Carbonpfeile sind sorgfältig ausbalanciert und bieten so Kraft und Präzision.\r\nDie CenterPoint-Carbonpfeile sind für Armbrüste konzipiert, die 20-Zoll-Armbrustpfeile verwenden.\r\nHergestellt mit dem idealen Gewicht für Ihre CenterPoint-Armbrust, wiegt jeder Pfeil 400 Grain, wenn er mit 100 Grain-Feldspitzen (separat erhältlich) ausgestattet ist.\r\n.003-Zoll Geradheitstoleranz\r\nDas CenterPoint Carbon Arrow 6er-Pack wird mit vorinstallierten Halbmondnocken geliefert, die so geformt sind, dass die Sehne beim Abfeuern nicht über oder unter den Pfeil rutscht. Dies bedeutet einen konstanten Kontakt zwischen Sehne und Nocke.\r\nEr ist lang genug, um die Genauigkeit zu verbessern, aber kurz genug, um zu viel Luftwiderstand zu vermeiden. Jeder 20-Zoll-Armbrustpfeil ist außerdem mit deltaförmigen Blazer-Federbeinen befiedert, die dem Pfeil Stabilität und Drehung verleihen.', 99.00, NULL, 1, 0.00, '', 'https://web.lweb.ch/usa/img/armbrust_zubehor/A046600', 'centerpoint', '2026-04-30 15:17:56', '2026-05-05 14:46:51', 'armbrustpfeile-und-bolzen', 1, NULL, NULL, NULL, 'ssa', 0.200),
(1017923935, 'A046079', 'ROCKY MOUNTAIN RM-415 ARMBRUST 200 LBS 415 FPS', 'Rocky Mountain RM-415 Armbrust 200 lbs 415 FPS h2>\r\nLeistung 200 lbs\r\nGeschwindigkeit der Pfeile 415 FPS\r\nVerfügbare Farbe: Tarnung\r\n\r\n215 lbs Zweige', 599.00, NULL, 1, 0.00, '', 'https://web.lweb.ch/usa/img/armbrust/A046079', 'Rocky Mountain', '2026-04-30 15:16:39', '2026-05-05 09:19:31', 'compound-armbrust', 0, NULL, NULL, NULL, 'SSA', 10.000),
(1018071032, 'A041257', 'Excalibur Micro MAG 340', 'Die Micro Mag 340 ist kompakt, leicht und leise und bietet in ihrer Klasse eine unübertroffene Performance. Die Mag 340 ist mit einem Aluminiumrahmen', 959.00, NULL, 1, 0.00, '', 'https://web.lweb.ch/usa/img/armbrust/A041257', 'Excalibur', '2026-04-30 15:16:39', '2026-05-05 09:18:06', 'recurve-armbrust', 1, NULL, NULL, NULL, 'SSA', 10.000),
