(1020864534, 'A010998', 'Portable Target Storm 2-25', 'Shot blocker Hurricane Storm II bis FPS 600+\r\nFeatures:\r\n\r\nAvailable in 25\"\r\n600 FPS+ stopping power\r\nUltra durable\r\nEasy 2 finger arrow removal\r\nBuilt to weather nearly any circumstance the new Hurricane Storm II targets are extremely durable and is designed to stop field-tipped arrows and crossbow bolts shot at up to 600+ fps while still maintaining effortless arrow removal. Measuring either 25x25x12 inches the Storm II targets are super-stuffed versions of their predecessor with high-contrast Hurricane aiming points and offset bullseyes for longer target life.', 129.00, NULL, 1, 0.00, '', 'https://web.lweb.ch/usa/img/armbrustzubehor/A010998', 'Hurricane', '2026-04-30 15:17:56', '2026-05-05 14:44:42', 'ziele', 0, NULL, NULL, NULL, 'SSA', 10.000),
(1020864535, 'A010997', 'Portable Target Storm 2-20', 'Shot blocker Hurricane Storm II bis FPS 600+\r\nFeatures:\r\n\r\nAvailable in 20\" \r\n600 FPS+ stopping power\r\nUltra durable\r\nEasy 2 finger arrow removal\r\nBuilt to weather nearly any circumstance the new Hurricane Storm II targets are extremely durable and is designed to stop field-tipped arrows and crossbow bolts shot at up to 600+ fps while still maintaining effortless arrow removal. Measuring either 20x24x10 inches the Storm II targets are super-stuffed versions of their predecessor with high-contrast Hurricane aiming points and offset bullseyes for longer target life.', 109.00, NULL, 1, 0.00, '', 'https://web.lweb.ch/usa/img/armbrustzubehor/A010997', 'Hurricane', '2026-04-30 15:17:56', '2026-05-05 14:44:30', 'ziele', 0, NULL, NULL, NULL, 'SSA', 10.000),
(1035877460, '111621DAM', 'Special Run Merlin Damast Meisterwerk', 'Ein echtes Meisterwerk, und ein wahrer Leckerbissen für alle Liebhaber des exklusiven Materials Damast! Damastklingen haben bei Böker eine lange Tradi', 949.00, NULL, 1, 0.00, '', 'https://web.lweb.ch/usa/img/messer/111621DAM', 'Böker', '2026-04-30 15:18:29', '2026-05-05 09:05:28', 'klappmesser', 0, NULL, NULL, NULL, 'Böker', 0.500),
(1039614351, 'BY03GP2', 'BYRD CARA CARA 2 G-10', 'Spydercos Byrd Messerlinie bietet all die Funktionalität und allen Komfort der Hauptproduktlinie zu einem Preis, der sie zweifellos zur besten Wertsch', 87.00, NULL, 1, 0.00, '', 'https://web.lweb.ch/usa/img/messer/BY03GP2', 'Spyderco', '2026-04-30 15:18:29', '2026-05-05 08:25:30', 'klappmesser', 2, NULL, NULL, NULL, 'Klötzli', 0.500),
(1041661708, 'CST-97KMIGS', 'Royal Kukri Machete mit Scheide', 'Royal Kukri Machete mit Scheide\r\n\r\nEin gutes Kukri ist ein unerschütterlicher Partner in einer Notsituation und ein unentbehrliches Überlebensinstrume', 59.00, NULL, 1, 0.00, '', 'https://web.lweb.ch/usa/img/messer/CST-97KMIGS', 'Cold Steel', '2026-04-30 15:18:29', '2026-05-05 09:04:07', 'feste-klinge', 1, NULL, NULL, NULL, 'Coldsteel', 0.500),
(1085573207, 'UPOLD Siege Mag8_15', '8 Schuss Spezial Magazin 15\" zu Siege 300', 'Produktbeschreibung\r\n\r\nSpezial Magazin mit 8 Bolzen für Cobra Siege EK Archery Armbrust, das bis zu 8 Bolzen der EK Archery R-Serie (zweiflügelig) oder kompatible Bolzen aufnehmen kann. Eine einfache Lösung, um ein Upgrade in etwa 15 Minuten durchzuführen.\r\n\r\nPaket Inhalt:\r\n1. Magazin zur Aufnahme von 8 Schrauben der R-Serie + Picatinny-Winkeleinstellplatte (1 Grad)\r\n2. Seitliche Ersatzschrauben zur Magazinfixierung\r\n3. Vorderer Bolzenhalter zur Bolzenfixierung am vorderen Teil der Armbrust\r\n4. Benötigte Schrauben für frontseitige Halterungsmontage\r\n5. Sechsecke für den Installationsvorgang\r\n* Optional - Klebertube kann enthalten sein (um den Picatinny-Schienenversteller zu fixieren)\r\n\r\nBitte beachten Sie:\r\nDie in den Abbildungen gezeigten Bolzen, die Cobra Siege-Armbrust und die optischen Zielgeräte sind nicht Bestandteil des Pakets.', 239.00, '69f5b558c07cf_1777710424_0.png', 1, 0.00, '', 'https://web.lweb.ch/usa/img/armbrust_zubehor/UPOLD Siege Mag8_15', 'UPBOLT', '2026-04-30 15:17:56', '2026-05-02 08:27:04', 'armbrust-zubehoer', 1, NULL, NULL, NULL, 'UPBOLT', 1.000),
