(1131640752, '01RU004', 'Taschenmesser Rui Mohican III Pocket', 'Die kompakte, klappbare Version des Mohican III, mit einer einhändig zu bedienenden Klinge mit Linerlock-Verriegelung. Die mit einem detallierten Camo', 39.00, NULL, 1, 0.00, '', 'https://web.lweb.ch/usa/img/messer/01RU004', 'Rui', '2026-04-30 15:18:29', '2026-05-05 09:07:36', 'klappmesser', 2, NULL, NULL, NULL, 'Böker', 0.500),
