INSERT INTO `products` (`id`, `article_number`, `name`, `description`, `price`, `image`, `heat_level`, `rating`, `badge`, `image_url`, `origin`, `created_at`, `updated_at`, `category`, `stock`, `image2`, `image3`, `image4`, `supplier`, `weight_kg`) VALUES
(1253490782, '05ZS518', 'Magnum Hattori Hanzo Set', 'Diese Schwerter sind einem der bekanntesten Samurai, Hattori Hanzo, gewidmet, der 1541 in der Provinz Mikawa geboren wurde. In der Nachbarprovinz Koga ist die Geburtsstätte des Ninjutsu und auch der Ninja. Unter diesen Voraussetzungen wuchs er zu einem ausgezeichneten Kämpfer heran. Seine erste Schlacht schlug er im Alter von nur 16 Jahren und gelangte so schnell zu Lob und Anerkennung. Die Klingen bestehen aus Kohlenstoffstahl und verfügen über einen dekorativen Anschliff. Die traditionell gewickelten Griffe sind mit Menukis und einer rochenhautartigen Unterlage versehen. Die Tsubas aus Zinkdruckguss sind alle mit gleichmäßigen Durchbrüchen versehen. An den Scheiden sind sämtliche Beschläge mit Ornamenten geschmückt. Dieses umfangreiche Set besteht aus einem Tanto, einem Wakizashi, einem Katana und einem schwarz lackiertem Schwertständer. Tanto: Gesamtlänge 53 cm. Klinge 28 cm. Stärke 4 mm. Gewicht 650 g. Wakizashi: Gesamtlänge 78 cm. Klinge 48 cm. Stärke 4 mm. Gewicht 900 g. Katana: Gesamtlänge 103 cm. Klinge 68 cm. Stärke 4 mm. Gewicht 1050 g.\r\n\r\nDeko- bzw. Sammlerschwert, nicht zum Einsatz geeignet.', 159.00, NULL, 1, 0.00, '', 'https://web.lweb.ch/usa/img/messer/05ZS518', 'Böker', '2026-04-30 15:18:29', '2026-05-05 08:58:07', 'feste-klinge', 2, NULL, NULL, NULL, 'Böker', 0.500),
(1253597553, 'BPR-C-PULSE-6', 'Recurve Bogen Set Core Pulse', 'Der 3-teilige CORE Pulse Recurvebogen mit feiner Holzlaminierung und glasfiberverstärkten Wurfarmen ist in verschiedenen Längen und Zugstärken erhältlich. Er ist bereits mit je einer Visier- und Buttonbuchse (5/16 x 24) ausgestattet und eignet sich gerade für Anfänger hervorragend. Kann aber natürlich auch von jedem anderen Schützen benutzt werden.\r\nDie Wurfarme sind in weiss gehalten und bestehen aus mit Fiberglaslaminat überzogenem Holz.\r\n\r\nverfügbare Bogenlängen: \r\n\r\n\r\n- 66 Zoll (mit 24 Zoll Mittelstück)\r\n- 68 Zoll (mit 24 Zoll Mittelstück)\r\n\r\n\r\nverfügbare Zuggewichte: \r\n\r\n20-32 lbs (in 4 lbs Schritten)\r\n\r\n\r\nLieferumfang:\r\n- Bogen inkl. Sehne (Dacron)\r\n- Bogentasche\r\n- 3 Pfeile\r\n- Armschutz\r\n- Zielvorrichtung\r\n- Spanngurt\r\n- Pfeilauflage\r\n\r\nBild kann vom Original leicht abweichen', 149.00, NULL, 1, 0.00, '', 'https://web.lweb.ch/usa/img/pfeilbogen/BPR-C-PULSE-6', 'Core', '2026-04-30 15:19:51', '2026-05-05 16:04:38', 'recurve-bogen', 0, NULL, NULL, NULL, 'SSA', 2.100),
